// CreatePrivateKeyDeterministic uses test vectors to create a deterministic private key for testing.
// https://datatracker.ietf.org/doc/html/draft-ietf-lamps-pq-composite-sigs-14#appendix-E.
func CreatePrivateKeyDeterministic(t *testing.T, mlDSAInstanceInt compositemldsa.MLDSAInstance, classicalAlgorithmInt compositemldsa.ClassicalAlgorithm) (*mldsa.PrivateKey, key.Key) {
	t.Helper()
	mlDSAInstance := compositemldsa.MLDSAInstance(mlDSAInstanceInt)
	classicalAlgorithm := compositemldsa.ClassicalAlgorithm(classicalAlgorithmInt)
	mlDSAParams, err := compositemldsa.ParametersForMLDSA(mlDSAInstance)
	if err != nil {
		t.Fatalf("Failed to get ML-DSA parameters: %v", err)
	}
	classicalParams, err := compositemldsa.ParametersForClassicalAlgorithm(classicalAlgorithm)
	if err != nil {
		t.Fatalf("Failed to get classical parameters: %v", err)
	}

	var mlDSASeedHex string
	var classPrivKey key.Key

	switch mlDSAInstance {
	case compositemldsa.MLDSA65:
		switch classicalAlgorithm {
		case compositemldsa.Ed25519:
			mlDSASeedHex = hexMlDsa65PrivSeedForEd25519
			classPrivKey, err = ed25519.NewPrivateKey(mustSecretBytes(t, hexMlDsa65Ed25519Priv), 0, *classicalParams.(*ed25519.Parameters))
		case compositemldsa.ECDSAP256:
			mlDSASeedHex = hexMlDsa65PrivSeedForEcdsaP256
			classPrivKey, err = ecdsa.NewPrivateKey(mustSecretBytes(t, hexMlDsa65EcdsaP256Priv), 0, classicalParams.(*ecdsa.Parameters))
		case compositemldsa.ECDSAP384:
			mlDSASeedHex = hexMlDsa65PrivSeedForEcdsaP384
			classPrivKey, err = ecdsa.NewPrivateKey(mustSecretBytes(t, hexMlDsa65EcdsaP384Priv), 0, classicalParams.(*ecdsa.Parameters))
		case compositemldsa.RSA3072PSS:
			mlDSASeedHex = hexMlDsa65PrivSeedForRsa3072Pss
			var pubKey *rsassapss.PublicKey
			pubKey, err = rsassapss.NewPublicKey(mustHexDecode(t, hexMlDsa65Rsa3072PssN), 0, classicalParams.(*rsassapss.Parameters))
			if err == nil {
				classPrivKey, err = rsassapss.NewPrivateKey(pubKey, rsassapss.PrivateKeyValues{
					P: mustSecretBytes(t, hexMlDsa65Rsa3072PssP),
					Q: mustSecretBytes(t, hexMlDsa65Rsa3072PssQ),
					D: mustSecretBytes(t, hexMlDsa65Rsa3072PssD),
				})
			}
		case compositemldsa.RSA4096PSS:
			mlDSASeedHex = hexMlDsa65PrivSeedForRsa4096Pss
			var pubKey *rsassapss.PublicKey
			pubKey, err = rsassapss.NewPublicKey(mustHexDecode(t, hexMlDsa65Rsa4096PssN), 0, classicalParams.(*rsassapss.Parameters))
			if err == nil {
				classPrivKey, err = rsassapss.NewPrivateKey(pubKey, rsassapss.PrivateKeyValues{
					P: mustSecretBytes(t, hexMlDsa65Rsa4096PssP),
					Q: mustSecretBytes(t, hexMlDsa65Rsa4096PssQ),
					D: mustSecretBytes(t, hexMlDsa65Rsa4096PssD),
				})
			}
		case compositemldsa.RSA3072PKCS1:
			mlDSASeedHex = hexMlDsa65PrivSeedForRsa3072Pkcs1
			var pubKey *rsassapkcs1.PublicKey
			pubKey, err = rsassapkcs1.NewPublicKey(mustHexDecode(t, hexMlDsa65Rsa3072Pkcs1N), 0, classicalParams.(*rsassapkcs1.Parameters))
			if err == nil {
				classPrivKey, err = rsassapkcs1.NewPrivateKey(pubKey, rsassapkcs1.PrivateKeyValues{
					P: mustSecretBytes(t, hexMlDsa65Rsa3072Pkcs1P),
					Q: mustSecretBytes(t, hexMlDsa65Rsa3072Pkcs1Q),
					D: mustSecretBytes(t, hexMlDsa65Rsa3072Pkcs1D),
				})
			}
		case compositemldsa.RSA4096PKCS1:
			mlDSASeedHex = hexMlDsa65PrivSeedForRsa4096Pkcs1
			var pubKey *rsassapkcs1.PublicKey
			pubKey, err = rsassapkcs1.NewPublicKey(mustHexDecode(t, hexMlDsa65Rsa4096Pkcs1N), 0, classicalParams.(*rsassapkcs1.Parameters))
			if err == nil {
				classPrivKey, err = rsassapkcs1.NewPrivateKey(pubKey, rsassapkcs1.PrivateKeyValues{
					P: mustSecretBytes(t, hexMlDsa65Rsa4096Pkcs1P),
					Q: mustSecretBytes(t, hexMlDsa65Rsa4096Pkcs1Q),
					D: mustSecretBytes(t, hexMlDsa65Rsa4096Pkcs1D),
				})
			}
		}
	case compositemldsa.MLDSA87:
		switch classicalAlgorithm {
		case compositemldsa.ECDSAP384:
			mlDSASeedHex = hexMlDsa87PrivSeedForEcdsaP384
			classPrivKey, err = ecdsa.NewPrivateKey(mustSecretBytes(t, hexMlDsa87EcdsaP384Priv), 0, classicalParams.(*ecdsa.Parameters))
		case compositemldsa.ECDSAP521:
			mlDSASeedHex = hexMlDsa87PrivSeedForEcdsaP521
			classPrivKey, err = ecdsa.NewPrivateKey(mustSecretBytes(t, hexMlDsa87EcdsaP521Priv), 0, classicalParams.(*ecdsa.Parameters))
		case compositemldsa.RSA3072PSS:
			mlDSASeedHex = hexMlDsa87PrivSeedForRsa3072Pss
			var pubKey *rsassapss.PublicKey
			pubKey, err = rsassapss.NewPublicKey(mustHexDecode(t, hexMlDsa87Rsa3072PssN), 0, classicalParams.(*rsassapss.Parameters))
			if err == nil {
				classPrivKey, err = rsassapss.NewPrivateKey(pubKey, rsassapss.PrivateKeyValues{
					P: mustSecretBytes(t, hexMlDsa87Rsa3072PssP),
					Q: mustSecretBytes(t, hexMlDsa87Rsa3072PssQ),
					D: mustSecretBytes(t, hexMlDsa87Rsa3072PssD),
				})
			}
		case compositemldsa.RSA4096PSS:
			mlDSASeedHex = hexMlDsa87PrivSeedForRsa4096Pss
			var pubKey *rsassapss.PublicKey
			pubKey, err = rsassapss.NewPublicKey(mustHexDecode(t, hexMlDsa87Rsa4096PssN), 0, classicalParams.(*rsassapss.Parameters))
			if err == nil {
				classPrivKey, err = rsassapss.NewPrivateKey(pubKey, rsassapss.PrivateKeyValues{
					P: mustSecretBytes(t, hexMlDsa87Rsa4096PssP),
					Q: mustSecretBytes(t, hexMlDsa87Rsa4096PssQ),
					D: mustSecretBytes(t, hexMlDsa87Rsa4096PssD),
				})
			}
		}
	}

	if err != nil {
		t.Fatalf("Failed to create classical private key: %v", err)
	}

	mlDSAPrivKey, err := mldsa.NewPrivateKey(mustSecretBytes(t, mlDSASeedHex), 0, mlDSAParams)
	if err != nil {
		t.Fatalf("Failed to create ML-DSA private key: %v", err)
	}

	return mlDSAPrivKey, classPrivKey
}

func mustHexDecode(t *testing.T, s string) []byte {
	t.Helper()
	b, err := hex.DecodeString(s)
	if err != nil {
		t.Fatalf("hex.DecodeString err = %v", err)
	}
	return b
}

func mustSecretBytes(t *testing.T, s string) secretdata.Bytes {
	t.Helper()
	return secretdata.NewBytesFromData(mustHexDecode(t, s), insecuresecretdataaccess.Token{})
}

// GenerateMLDSAKeyPair uses the global registry to generate a random ML-DSA key pair.
func GenerateMLDSAKeyPair(t *testing.T, instanceInt compositemldsa.MLDSAInstance) (*mldsa.PrivateKey, *mldsa.PublicKey) {
	t.Helper()
	instance := compositemldsa.MLDSAInstance(instanceInt)
	var params *mldsa.Parameters
	var err error
	switch instance {
	case compositemldsa.MLDSA65:
		params, err = mldsa.NewParameters(mldsa.MLDSA65, mldsa.VariantNoPrefix)
	case compositemldsa.MLDSA87:
		params, err = mldsa.NewParameters(mldsa.MLDSA87, mldsa.VariantNoPrefix)
	default:
		t.Fatalf("unsupported ML-DSA instance: %v", instance)
	}
	if err != nil {
		t.Fatalf("mldsa.NewParameters err = %v", err)
	}
	priv, err := keygenregistry.CreateKey(params, 0)
	if err != nil {
		t.Fatalf("keygenregistry.CreateKey err = %v", err)
	}
	mlDSAPriv := priv.(*mldsa.PrivateKey)
	pub, err := mlDSAPriv.PublicKey()
	if err != nil {
		t.Fatalf("mlDSAPriv.PublicKey() err = %v", err)
	}
	return mlDSAPriv, pub.(*mldsa.PublicKey)
}

// GenerateClassicalKeyPair uses the global registry to generate a random classical key pair.
func GenerateClassicalKeyPair(t *testing.T, classicalAlgorithmInt compositemldsa.ClassicalAlgorithm, params key.Parameters) (key.Key, key.Key) {
	t.Helper()
	classicalAlgorithm := compositemldsa.ClassicalAlgorithm(classicalAlgorithmInt)
	priv, err := keygenregistry.CreateKey(params, 0)
	if err != nil {
		t.Fatalf("keygenregistry.CreateKey for %v err = %v", classicalAlgorithm, err)
	}

	var pub key.Key
	switch classicalAlgorithm {
	case compositemldsa.Ed25519:
		pub, err = priv.(*ed25519.PrivateKey).PublicKey()
	case compositemldsa.ECDSAP256, compositemldsa.ECDSAP384, compositemldsa.ECDSAP521:
		pub, err = priv.(*ecdsa.PrivateKey).PublicKey()
	case compositemldsa.RSA3072PSS, compositemldsa.RSA4096PSS:
		pub, err = priv.(*rsassapss.PrivateKey).PublicKey()
	case compositemldsa.RSA3072PKCS1, compositemldsa.RSA4096PKCS1:
		pub, err = priv.(*rsassapkcs1.PrivateKey).PublicKey()
	}
	if err != nil {
		t.Fatalf("PublicKey for %v err = %v", classicalAlgorithm, err)
	}
	return priv, pub
}

// CreatePrivateKeyRandom uses CreateMLDSAKeyPair and CreateClassicalKeyPair to generate a random composite ML-DSA key pair.
func CreatePrivateKeyRandom(t *testing.T, mlDSAInstance compositemldsa.MLDSAInstance, classicalAlgorithm compositemldsa.ClassicalAlgorithm) (*mldsa.PrivateKey, key.Key) {
	t.Helper()
	mlDSAPrivKey, _ := GenerateMLDSAKeyPair(t, mlDSAInstance)
	classicalParams, err := compositemldsa.ParametersForClassicalAlgorithm(compositemldsa.ClassicalAlgorithm(classicalAlgorithm))
	if err != nil {
		t.Fatalf("ParametersForClassicalAlgorithm(%v) err = %v", classicalAlgorithm, err)
	}
	classicalPrivKey, _ := GenerateClassicalKeyPair(t, classicalAlgorithm, classicalParams)

	return mlDSAPrivKey, classicalPrivKey
}

// TestParameter serves as an internal mirror structure for the Parameter struct of the public compositemldsa package.
type TestParameter struct {
	ClassicalAlgorithm compositemldsa.ClassicalAlgorithm
	Instance           compositemldsa.MLDSAInstance
	Variant            compositemldsa.Variant
	ClassicalParams    key.Parameters
}

func mustParams(t *testing.T, algo compositemldsa.ClassicalAlgorithm) key.Parameters {
	t.Helper()
	p, err := compositemldsa.ParametersForClassicalAlgorithm(algo)
	if err != nil {
		t.Fatalf("ParametersForClassicalAlgorithm(%v) failed: %v", algo, err)
	}
	return p
}

// TestCasesSupportedParameters returns the supported parameters for all test cases.
func TestCasesSupportedParameters(t *testing.T) []TestParameter {
	t.Helper()
	return []TestParameter{
		{compositemldsa.Ed25519, compositemldsa.MLDSA65, compositemldsa.VariantTink, mustParams(t, compositemldsa.Ed25519)},
		{compositemldsa.Ed25519, compositemldsa.MLDSA65, compositemldsa.VariantNoPrefix, mustParams(t, compositemldsa.Ed25519)},
		{compositemldsa.ECDSAP256, compositemldsa.MLDSA65, compositemldsa.VariantTink, mustParams(t, compositemldsa.ECDSAP256)},
		{compositemldsa.ECDSAP256, compositemldsa.MLDSA65, compositemldsa.VariantNoPrefix, mustParams(t, compositemldsa.ECDSAP256)},
		{compositemldsa.ECDSAP384, compositemldsa.MLDSA65, compositemldsa.VariantTink, mustParams(t, compositemldsa.ECDSAP384)},
		{compositemldsa.ECDSAP384, compositemldsa.MLDSA65, compositemldsa.VariantNoPrefix, mustParams(t, compositemldsa.ECDSAP384)},
		{compositemldsa.RSA3072PKCS1, compositemldsa.MLDSA65, compositemldsa.VariantTink, mustParams(t, compositemldsa.RSA3072PKCS1)},
		{compositemldsa.RSA3072PKCS1, compositemldsa.MLDSA65, compositemldsa.VariantNoPrefix, mustParams(t, compositemldsa.RSA3072PKCS1)},
		{compositemldsa.ECDSAP384, compositemldsa.MLDSA87, compositemldsa.VariantTink, mustParams(t, compositemldsa.ECDSAP384)},
		{compositemldsa.ECDSAP384, compositemldsa.MLDSA87, compositemldsa.VariantNoPrefix, mustParams(t, compositemldsa.ECDSAP384)},
		{compositemldsa.ECDSAP521, compositemldsa.MLDSA87, compositemldsa.VariantTink, mustParams(t, compositemldsa.ECDSAP521)},
		{compositemldsa.ECDSAP521, compositemldsa.MLDSA87, compositemldsa.VariantNoPrefix, mustParams(t, compositemldsa.ECDSAP521)},
		{compositemldsa.RSA4096PSS, compositemldsa.MLDSA87, compositemldsa.VariantTink, mustParams(t, compositemldsa.RSA4096PSS)},
		{compositemldsa.RSA4096PSS, compositemldsa.MLDSA87, compositemldsa.VariantNoPrefix, mustParams(t, compositemldsa.RSA4096PSS)},
	}
}
